// Normalize Evolution API payload + classify intent
const b = $input.first().json;
const body = b.body || b;
const data = body.data || {};
const key = data.key || {};
const jid = key.remoteJid || '';
const fromMe = !!key.fromMe;
const msg = data.message || {};
const text = (msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || '').trim();
const participant = key.participant || '';
const pushName = data.pushName || '';

const DASHBOARD = '120363427557786772@g.us';
const PYP = '120363399646672357@g.us';
const KNOWN_RIDERS = ['bryant','robert','hector','omar','wilmer','luis','anderson','caldera','ostos','vargas','fabian','diego','johan','kevin','kelvin','abraham','oguir','leonel','ronald','jaider','riyeson','gustavo','marcos','daniela','larry','miguel','farfan','jhosty'];

let intent = 'ignore';
let detectedRider = null;
if (!fromMe && text) {
  if (jid === DASHBOARD) {
    if (/^delivery\b/i.test(text)) intent = 'delivery';
    else if (/^(recibido|cobrado)\b/i.test(text)) intent = 'recibido';
    else if (/^pagado\b/i.test(text)) intent = 'pagado';
    else if (/^saldo$/i.test(text)) intent = 'saldo';
    else if (/^envio\b/i.test(text)) intent = 'envio';
    else if (/^gasto\b/i.test(text)) intent = 'gasto';
    else if (/^cambio\b/i.test(text)) intent = 'cambio';
    else if (/^pagopyp\b/i.test(text)) intent = 'pagopyp';
  } else if (jid === PYP) {
    // "recibido $XX rider" — Aniello writes this in PyP group
    if (/^(recibido|cobrado)\b/i.test(text)) {
      intent = 'recibido';
    } else {
      // Rider name detection (single word = motorizado assigned)
      const firstWord = text.split(/\s+/)[0].toLowerCase().replace(/[^a-záéíóúñ]/gi,'');
      if (KNOWN_RIDERS.includes(firstWord)) { intent = 'rider'; detectedRider = firstWord; }
    }
  }
}
return [{ json: { intent, jid, text, fromMe, participant, pushName, detectedRider, DASHBOARD, PYP } }];

// Flow A parse
const t = $json.text;
const orderMatch = t.match(/#(\d+)/);
const phoneMatch = t.match(/\b(58\d{10}|0?\d{10,11})\b/);
const cobrarMatch = t.match(/cobrar\s*\$?\s*([\d.,]+)/i);
const isPaid = /\bpagado\b/i.test(t) && !cobrarMatch;
const orderNumber = orderMatch ? orderMatch[1] : null;
let phone = phoneMatch ? phoneMatch[1] : null;
if (phone && phone.startsWith('0')) phone = '58' + phone.slice(1);
else if (phone && !phone.startsWith('58')) phone = '58' + phone;
const amountToCollect = cobrarMatch ? parseFloat(String(cobrarMatch[1]).replace(/,/g,'')) : null;

// Name: between #XXXX and phone
let clientName = null;
if (orderMatch && phoneMatch) {
  const afterOrder = t.slice(t.indexOf(orderMatch[0]) + orderMatch[0].length);
  const phoneIdx = afterOrder.indexOf(phoneMatch[0]);
  if (phoneIdx > 0) clientName = afterOrder.slice(0, phoneIdx).trim();
}

// Address: after 'destino' up to 'cobrar' / 'pagado'
const destMatch = t.match(/destino\s+(.+?)(?=\s+(cobrar|pagado)\b|$)/is);
const address = destMatch ? destMatch[1].trim() : null;

return [{ json: { orderNumber, clientName, phone, address, amountToCollect, isPaid, isCashOnDelivery: !!cobrarMatch, _src: $json } }];

const parsed = $('A: Parse delivery').first().json;
const orderRow = ($input.first().json && $input.first().json[0]) || null;
const orderId = orderRow?.id || null;
return [{ json: { ...parsed, orderId, orderMatchFound: !!orderRow, clientNameFromDb: orderRow?.client_name || null } }];

const rider = $('Route intent').first().json.detectedRider;
const rows = $input.first().json;
const row = Array.isArray(rows) ? rows[0] : null;
if (!row) return [{ json: { noPending: true, rider } }];
return [{ json: { id: row.id, order_id: row.order_id, destination: row.destination, rider } }];

// Flow C parse: 'recibido $XX rider' | 'recibido $XX' | 'cobrado #XXXX $XX'
const t = $json.text;
const amountMatch = t.match(/\$\s*([\d.,]+)/) || t.match(/\b([\d.,]+)\b/);
const amount = amountMatch ? parseFloat(String(amountMatch[1]).replace(/,/g,'')) : null;
const orderMatch = t.match(/#(\d+)/);
const words = t.toLowerCase().split(/\s+/);
const KNOWN = ['bryant','robert','hector','omar','wilmer','luis','anderson','caldera','ostos','vargas','fabian','diego','johan','kevin','kelvin','abraham','oguir','leonel','ronald','jaider','riyeson','gustavo','marcos','daniela','larry','miguel','farfan','jhosty'];
const rider = words.find(w => KNOWN.includes(w.replace(/[^a-z]/g,''))) || null;
return [{ json: { amount, rider: rider ? rider.replace(/[^a-z]/g,'') : null, orderNumber: orderMatch ? orderMatch[1] : null } }];

// Flow D parse: 'pagado #XXXX method $amt' or 'pagado #XXXX mixto cash $X zelle $Y'
const t = $json.text;
const orderMatch = t.match(/#(\d+)/);
const orderNumber = orderMatch ? orderMatch[1] : null;
const lower = t.toLowerCase();
const isMixto = /\bmixto\b/.test(lower);

// Find all method+amount pairs
const payments = [];
const re = /(cash|efectivo|zelle|bs|bolivares|bolívares|binance)\s*\$?\s*([\d.,]+)/gi;
let m;
while ((m = re.exec(t)) !== null) {
  let method = m[1].toLowerCase();
  if (method === 'efectivo') method = 'cash';
  if (method === 'bs' || method === 'bolivares' || method === 'bolívares') method = 'bolivares';
  const amount = parseFloat(String(m[2]).replace(/,/g,''));
  if (amount > 0) payments.push({ method, amount });
}

const methodForOrder = payments.length === 1 ? payments[0].method : (isMixto ? 'mixto' : (payments[0]?.method || null));
return [{ json: { orderNumber, payments, methodForOrder } }];

// Calculate balances from cash_movements
const movements = $('E: Fetch balances').first().json;
const rateData = $('E: Fetch rate').first().json;
const rate = rateData.Bs || 1;

// movements might be a single object or array
const movementsArr = $('E: Fetch balances').all().map(i => i.json);

const balances = { cash_usd: 0, zelle: 0, binance: 0, bolivares: 0 };

for (const r of movementsArr) {
  const w = r.wallet;
  const amt = parseFloat(r.amount) || 0;
  if (!balances.hasOwnProperty(w)) continue;
  if (r.movement_type === 'ingreso') balances[w] += amt;
  else if (r.movement_type === 'egreso') balances[w] -= amt;
  else if (r.movement_type === 'cambio') balances[w] += amt;
  else if (r.movement_type === 'transferencia') balances[w] += amt;
}

const fmtNum = (n, decimals) => {
  decimals = decimals != null ? decimals : 2;
  const abs = Math.abs(n);
  const parts = abs.toFixed(decimals).split('.');
  parts[0] = parts[0].replace(/B(?=(d{3})+(?!d))/g, ',');
  return (n < 0 ? '-' : '') + parts.join('.');
};

const bsInUsd = rate > 0 ? balances.bolivares / rate : 0;
const totalUsd = balances.cash_usd + balances.zelle + balances.binance + bsInUsd;

// Venezuela time (UTC-4)
const now = new Date();
const vzTime = new Date(now.getTime() - 4 * 60 * 60 * 1000);
const timeStr = vzTime.toISOString().replace('T', ' ').substring(0, 16);

const lines = [];
lines.push('*Saldos actuales*');
lines.push('');
lines.push('Cash USD:  $' + fmtNum(balances.cash_usd));
lines.push('Zelle:     $' + fmtNum(balances.zelle));
lines.push('Binance:   $' + fmtNum(balances.binance));
lines.push('Bolivares: Bs ' + fmtNum(balances.bolivares, 0) + '  (= $' + fmtNum(bsInUsd) + ')');
lines.push('');
lines.push('Total equivalente: $' + fmtNum(totalUsd));
lines.push('Tasa del dia: Bs ' + fmtNum(rate, 0) + '/USD');
lines.push(timeStr + ' VET');

const msg = lines.join(String.fromCharCode(10));

return [{ json: { message: msg } }];

