  zoom: 'zoom.red',
  tealca: 'tealca.com',
  domesa: 'domesa.com',
  dhl: 'dhl.com'
};
const trackUrl = trackingUrls[carrier] || '';

return [{ json: { orderNumber, carrier, tracking, trackUrl } }];

