return [{ json: { orderNumber, carrier, tracking, trackUrl } }];

// Merge parsed data with order data from lookup
const parsed = $('F: Parse envio').first().json;
const lookupResult = $('F: Lookup order').first().json;

const order = Array.isArray(lookupResult) ? lookupResult[0] : lookupResult;

const clientName = order?.client_name || '';
const clientPhone = order?.client_phone || '';
const clientCity = order?.client_city || '';
const hasPhone = !!(clientPhone && clientPhone.length > 5);

let cleanPhone = clientPhone.replace(/[^0-9]/g, '');
if (cleanPhone.startsWith('0')) cleanPhone = '58' + cleanPhone.substring(1);
if (!cleanPhone.startsWith('58') && cleanPhone.length === 10) cleanPhone = '58' + cleanPhone;

// Build dashboard confirmation message
let dashboardMsg = "\u2705 #" + parsed.orderNumber + " despachado por " + parsed.carrier.toUpperCase() + ". ";
if (hasPhone) {
  dashboardMsg += "Tracking enviado a " + (clientName || "cliente");
  if (clientCity) dashboardMsg += " (" + clientCity + ")";
  dashboardMsg += ".";
} else {
  dashboardMsg += "Tracking registrado.";
  dashboardMsg += "\n\u26a0\ufe0f Sin tel\u00e9fono registrado \u2014 tracking NO enviado al cliente.";
}

return [{ json: {
  orderNumber: parsed.orderNumber,
  carrier: parsed.carrier,
  tracking: parsed.tracking,
  trackUrl: parsed.trackUrl,
  clientName,
  clientPhone: cleanPhone,
  clientCity,
  hasPhone,
  dashboardMsg
}}];

// Parse: "gasto $25 gasolina" or "gasto $100 mercadería PyP" or "gasto $50 zelle comida"
const text = $json.text;

// Match amount (with or without $)
const m = text.match(/^gasto\s+\$?\s*([\d.,]+)\s+(.+)/i);
if (!m) throw new Error('Formato inválido. Usar: gasto $XX concepto');

const amount = parseFloat(m[1].replace(/,/g, ''));
let rest = m[2].trim();

// Check if first word of rest is a wallet name
const wallets = ['cash', 'cash_usd', 'zelle', 'bolivares', 'bs', 'binance'];
const firstWord = rest.split(/\s+/)[0].toLowerCase();
let wallet = 'cash_usd'; // default

if (wallets.includes(firstWord)) {
  if (firstWord === 'zelle') wallet = 'zelle';
  else if (firstWord === 'bolivares' || firstWord === 'bs') wallet = 'bolivares';
  else if (firstWord === 'binance') wallet = 'binance';
  else wallet = 'cash_usd';
  // Remove wallet word from concept
  rest = rest.split(/\s+/).slice(1).join(' ').trim();
}

const concept = rest || 'gasto sin concepto';

return [{ json: { amount, wallet, concept } }];

// Parse: "cambio $200 cash zelle" | "cambio $500 zelle cash" | "cambio $300 cash bs"
const text = $json.text;
const m = text.match(/^cambio\s+\$?\s*([\d.,]+)\s+(\S+)\s+(\S+)/i);
if (!m) throw new Error('Formato: cambio $XX origen destino');

const amount = parseFloat(m[1].replace(/,/g, ''));
const fromRaw = m[2].toLowerCase();
const toRaw = m[3].toLowerCase();

// Normalize wallet names
function norm(w) {
  if (w === 'cash' || w === 'cash_usd' || w === 'efectivo') return 'cash_usd';
  if (w === 'zelle') return 'zelle';
  if (w === 'bs' || w === 'bolivares' || w === 'bsf') return 'bolivares';
  if (w === 'binance') return 'binance';
  return w;
}

const fromWallet = norm(fromRaw);
const toWallet = norm(toRaw);

if (fromWallet === toWallet) throw new Error("Origen y destino no pueden ser iguales");

const needsRate = (fromWallet === 'bolivares' || toWallet === 'bolivares');

return [{ json: { amount, fromWallet, toWallet, fromRaw, toRaw, needsRate } }];

// Build egreso + ingreso movements for the cambio
const parsed = $('H: Parse cambio').first().json;
const rate = $('H: Fetch rate').first().json.Bs || 1;

const amount = parsed.amount;
const from = parsed.fromWallet;
const to = parsed.toWallet;

// Calculate amounts for each side
let fromAmount = amount;
let toAmount = amount;
let fromUsdEq = amount;
let toUsdEq = amount;

if (from === 'bolivares') {
  // Converting FROM bs: amount is in Bs, USD equivalent = amount / rate
  fromUsdEq = Math.round((amount / rate) * 100) / 100;
  toAmount = fromUsdEq;
  toUsdEq = fromUsdEq;
} else if (to === 'bolivares') {
  // Converting TO bs: amount is in USD, Bs equivalent = amount * rate
  toAmount = Math.round(amount * rate * 100) / 100;
  toUsdEq = amount;
}

const movements = [
  {
    movement_type: 'egreso',
    wallet: from,
    amount: fromAmount,
    amount_usd_equivalent: fromUsdEq,
    exchange_rate: rate,
    concept: 'Cambio ' + from.replace('cash_usd','cash') + ' → ' + to.replace('cash_usd','cash')
  },
  {
    movement_type: 'ingreso',
    wallet: to,
    amount: toAmount,
    amount_usd_equivalent: toUsdEq,
    exchange_rate: rate,
    concept: 'Cambio ' + from.replace('cash_usd','cash') + ' → ' + to.replace('cash_usd','cash')
  }
];

// Build dashboard message
let msg = '\u2705 Cambio registrado: $' + amount + ' ' + from.replace('cash_usd','cash') + ' \u2192 ' + to.replace('cash_usd','cash') + '.';
if (to === 'bolivares') msg += ' (Bs ' + toAmount.toLocaleString() + ' a tasa ' + rate + ')';
if (from === 'bolivares') msg += ' (Bs ' + fromAmount.toLocaleString() + ' = $' + fromUsdEq + ' a tasa ' + rate + ')';

return [{ json: { movements, dashboardMsg: msg, rate } }];

// Parse: "pagopyp $25" or "pagopyp $25 zelle" or "pagopyp $100 bs"
const text = $json.text;
const m = text.match(/^pagopyp\s+\$?\s*([\d.,]+)(?:\s+(\S+))?/i);
if (!m) throw new Error('Formato: pagopyp $XX [zelle|bs]');
const amount = parseFloat(m[1].replace(/,/g, ''));
const walletRaw = (m[2] || 'zelle').toLowerCase();
let wallet = 'zelle';
if (walletRaw === 'bs' || walletRaw === 'bolivares') wallet = 'bolivares';
else if (walletRaw === 'cash' || walletRaw === 'cash_usd') wallet = 'cash_usd';
return [{ json: { amount, wallet } }];
